template:
struct Book {
    [[SLOT title_field]]
    author: String,
    pages: u32,
}

fn create_book(title: String, author: String, pages: u32) -> Book {
    Book {
        title,
        author,
        pages,
    }
}

fn get_title([[SLOT book_param]]) -> &String {
    [[SLOT title_ref]]
}

fn main() {
    let book = create_book(
        String::from("The Rust Programming Language"),
        String::from("Steve Klabnik"),
        552,
    );
    println!("Title: {}", get_title(&book));
}
